/// {@category Data}
library;

// Dart imports:
import 'dart:ui';

// Flutter imports:
import 'package:flutter/foundation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/failure/bad_request_failure.dart';
import 'package:baseball_detector_flutter/l10n/l10n.dart';

typedef FailureDescription = String Function(L10n);

/// Represents all app failures
sealed class Failure implements Exception {
  final String type;
  final String code;
  final FailureDescription description;
  final Object? underlyingException;
  late final StackTrace stackTrace;

  Failure({
    required this.type,
    required this.code,
    required this.description,
    this.underlyingException,
    StackTrace? stackTrace,
  }) {
    this.stackTrace = stackTrace ?? StackTrace.current;
  }

  static L10n get _defaultL10n => lookupL10n(const Locale('en'));

  String get message => description(_defaultL10n);

  @override
  String toString() {
    return 'Failure.$type(${formatArgs()})';
  }

  String translate(L10n? l10n) {
    l10n ??= _defaultL10n;
    return '${description(l10n)} [$code]';
  }

  @protected
  String formatArgs() {
    return 'code: $code, description: ${description(_defaultL10n)}';
  }

  /// Creates a BadRequestFailure from response data
  static BadRequestFailure _createBadRequestFailure({
    required String code,
    required int status,
    FailureDescription? description,
    String? title,
    Object? response,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) {
    // Extract message from response if available
    String? message;
    if (response is Map<String, dynamic>) {
      message = response['message'] as String?;
    }

    // Use message-based factory if message is available
    if (message != null) {
      return BadRequestFailure.fromMessage(
        message,
        code: code,
        status: status,
        description: description,
        title: title,
        response: response,
        underlyingException: underlyingException,
        stackTrace: stackTrace,
      );
    }

    // Fallback to generic BadRequestFailure
    return BadRequestFailure(
      code: code,
      status: status,
      description: description,
      title: title,
      response: response,
      underlyingException: underlyingException,
      stackTrace: stackTrace,
    );
  }

  /// Represents http response error
  factory Failure.httpResponse({
    required String code,
    required int status,
    FailureDescription? description,
    String? title,
    Object? response,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) {
    return switch (status) {
      // 4xx Client Error
      400 => _createBadRequestFailure(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      401 => UnauthorizedFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      403 => ForbiddenFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      404 => NotFoundFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      413 => PayloadTooLargeFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      422 => UnprocessableEntityFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      // 5xx Server Error
      500 => InternalServerErrorFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      503 => ServiceUnavailableFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
      _ => UnknownHttpResponseFailure._(
          code: code,
          status: status,
          description: description,
          title: title,
          response: response,
          underlyingException: underlyingException,
          stackTrace: stackTrace,
        ),
    };
  }

  /// Represents request cancelled error
  factory Failure.requestCancelled({
    required String code,
    FailureDescription? description,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = RequestCancelledFailure._;

  /// Represents network error
  factory Failure.network({
    required String code,
    FailureDescription? description,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = NetworkFailure._;

  /// Represents timeout error
  factory Failure.timeout({
    required String code,
    FailureDescription? description,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = TimeoutFailure._;

  /// Represents invalid session error
  factory Failure.invalidSession({
    required String code,
    FailureDescription? description,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = InvalidSessionFailure._;

  /// Represents undefined error
  factory Failure.undefined({
    required String code,
    FailureDescription? description,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = UndefinedFailure._;

  /// Represents insufficient privileges error
  factory Failure.insufficientPrivileges({
    required String code,
    FailureDescription? description,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = InsufficientPrivilegesFailure._;

  /// Email address is not registered
  factory Failure.unregisteredEmail({
    required String code,
    required String email,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = UnregisteredEmailFailure._;

  /// Email address is not confirmed
  factory Failure.unconfirmedEmail({
    required String code,
    required String email,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = UnconfirmedEmailFailure._;

  /// Password is wrong
  factory Failure.incorrectPassword({
    required String code,
    required String email,
    Object? underlyingException,
    StackTrace? stackTrace,
  }) = IncorrectPasswordFailure._;
}

/// Represents http response error
abstract class HttpResponseFailure extends Failure {
  final int status;
  final String? title;
  final Object? response;

  HttpResponseFailure({
    required super.type,
    required super.code,
    required super.description,
    super.underlyingException,
    super.stackTrace,
    required this.status,
    this.title,
    this.response,
  });

  @override
  String formatArgs() {
    return '${super.formatArgs()}, status: $status, title: $title, response: $response';
  }
}

/// Base class for HTTP response failures with common constructor pattern
abstract class BaseHttpResponseFailure extends HttpResponseFailure {
  BaseHttpResponseFailure({
    required super.code,
    required super.type,
    required int defaultStatus,
    required FailureDescription defaultDescription,
    int? status,
    FailureDescription? description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          status: status ?? defaultStatus,
          description: description ?? defaultDescription,
        );
}

/// Represents 401 error
final class UnauthorizedFailure extends BaseHttpResponseFailure {
  UnauthorizedFailure._({
    required super.code,
    super.status,
    super.description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'unauthorized',
          defaultStatus: 401,
          defaultDescription: (l10n) => l10n.failure__unauthorized,
        );
}

/// Represents 403 error
final class ForbiddenFailure extends BaseHttpResponseFailure {
  ForbiddenFailure._({
    required super.code,
    super.status,
    super.description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'forbidden',
          defaultStatus: 403,
          defaultDescription: (l10n) => l10n.failure__forbidden,
        );
}

/// Represents 404 error
final class NotFoundFailure extends BaseHttpResponseFailure {
  NotFoundFailure._({
    required super.code,
    super.status,
    super.description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'notFound',
          defaultStatus: 404,
          defaultDescription: (l10n) => l10n.failure__not_found,
        );
}

/// Represents 413 error
final class PayloadTooLargeFailure extends BaseHttpResponseFailure {
  PayloadTooLargeFailure._({
    required super.code,
    super.status,
    super.description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'payloadTooLarge',
          defaultStatus: 413,
          defaultDescription: (l10n) => l10n.failure__payload_too_large,
        );
}

/// Represents 422 error. Request is valid format but not acceptable value.
final class UnprocessableEntityFailure extends BaseHttpResponseFailure {
  UnprocessableEntityFailure._({
    required super.code,
    super.status,
    super.description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'unprocessableEntity',
          defaultStatus: 422,
          defaultDescription: (l10n) => l10n.failure__unprocessable_entity,
        );
}

/// Represents 500 error
final class InternalServerErrorFailure extends BaseHttpResponseFailure {
  InternalServerErrorFailure._({
    required super.code,
    super.status,
    super.description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'internalServerError',
          defaultStatus: 500,
          defaultDescription: (l10n) => l10n.failure__internal_server_error,
        );
}

/// Represents 503 error
final class ServiceUnavailableFailure extends BaseHttpResponseFailure {
  ServiceUnavailableFailure._({
    required super.code,
    super.status,
    super.description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'serviceUnavailable',
          defaultStatus: 503,
          defaultDescription: (l10n) => l10n.failure__service_unavailable,
        );
}

/// Represents other http response error
final class UnknownHttpResponseFailure extends HttpResponseFailure {
  UnknownHttpResponseFailure._({
    required super.code,
    required super.status,
    FailureDescription? description,
    super.underlyingException,
    super.stackTrace,
    super.title,
    super.response,
  }) : super(
          type: 'unknownHttpResponse',
          description:
              description ?? (l10n) => l10n.failure__unknown_http_response,
        );
}

/// Base class for simple failures with common constructor pattern
abstract class _BaseFailure extends Failure {
  _BaseFailure._({
    required super.code,
    required super.type,
    required FailureDescription defaultDescription,
    FailureDescription? description,
    super.underlyingException,
    super.stackTrace,
  }) : super(
          description: description ?? defaultDescription,
        );
}

/// Represents request cancelled error
final class RequestCancelledFailure extends _BaseFailure {
  RequestCancelledFailure._({
    required super.code,
    super.description,
    super.underlyingException,
    super.stackTrace,
  }) : super._(
          type: 'requestCancelled',
          defaultDescription: (l10n) => l10n.failure__request_cancelled,
        );
}

/// Represents network error
final class NetworkFailure extends _BaseFailure {
  NetworkFailure._({
    required super.code,
    super.description,
    super.underlyingException,
    super.stackTrace,
  }) : super._(
          type: 'network',
          defaultDescription: (l10n) => l10n.failure__network,
        );
}

/// Represents timeout error
final class TimeoutFailure extends _BaseFailure {
  TimeoutFailure._({
    required super.code,
    super.description,
    super.underlyingException,
    super.stackTrace,
  }) : super._(
          type: 'timeout',
          defaultDescription: (l10n) => l10n.failure__timeout,
        );
}

/// Represents invalid session
final class InvalidSessionFailure extends _BaseFailure {
  InvalidSessionFailure._({
    required super.code,
    super.description,
    super.underlyingException,
    super.stackTrace,
  }) : super._(
          type: 'invalidSession',
          defaultDescription: (l10n) => l10n.failure__invalid_session,
        );
}

/// Represents insufficient privileges error
final class InsufficientPrivilegesFailure extends _BaseFailure {
  InsufficientPrivilegesFailure._({
    required super.code,
    super.description,
    super.underlyingException,
    super.stackTrace,
  }) : super._(
          type: 'insufficientPrivileges',
          defaultDescription: (l10n) => l10n.failure__insufficient_privileges,
        );
}

/// Represents undefined error
final class UndefinedFailure extends _BaseFailure {
  UndefinedFailure._({
    required super.code,
    super.description,
    super.underlyingException,
    super.stackTrace,
  }) : super._(
          type: 'undefined',
          defaultDescription: (l10n) => l10n.failure__undefined,
        );
}

/// Base class for authentication failures
abstract class AuthFailure extends Failure {
  final String email;

  AuthFailure({
    required super.type,
    required super.code,
    required super.description,
    required this.email,
    super.underlyingException,
